use std::rc::{Rc, Weak};
use std::cell::RefCell; #[derive(Debug)]
struct Node { value: i32, parent: RefCell<Weak<Node>>, // Weak reference to parent children: RefCell<Vec<Rc<Node>>>, // Strong references to children
} impl Node { fn new(value: i32) -> Rc<Self> { Rc::new(Node { value, parent: RefCell::new(Weak::new()), children: RefCell::new(Vec::new()), }) } fn add_child(parent: &Rc<Node>, child: Rc<Node>) { // Set parent weak reference *child.parent.borrow_mut() = Rc::downgrade(parent); // Add child strong reference parent.children.borrow_mut().push(child); }
} fn main() { let parent = Node::new(1); let child = Node::new(2); Node::add_child(&parent, child); // Access parent from child let parent_from_child = parent.children.borrow()[0] .parent .borrow() .upgrade(); // Convert weak to strong reference if let Some(parent_ref) = parent_from_child { println!("Child's parent value: {}", parent_ref.value); } println!("Parent strong count: {}", Rc::strong_count(&parent)); // 1 println!("Parent weak count: {}", Rc::weak_count(&parent)); // 1
}

