use std::rc::{Rc, Weak};
use std::cell::RefCell; trait Observer { fn notify(&self, message: &str);
} struct Subject { observers: RefCell<Vec<Weak<dyn Observer>>>,
} impl Subject { fn new() -> Self { Subject { observers: RefCell::new(Vec::new()), } } fn subscribe(&self, observer: Weak<dyn Observer>) { self.observers.borrow_mut().push(observer); } fn notify_all(&self, message: &str) { let mut observers = self.observers.borrow_mut(); observers.retain(|weak_observer| { if let Some(observer) = weak_observer.upgrade() { observer.notify(message); true // Keep this observer } else { false // Remove dead observer } }); }
} struct ConcreteObserver { id: String,
} impl Observer for ConcreteObserver { fn notify(&self, message: &str) { println!("Observer {} received: {}", self.id, message); }
} fn main() { let subject = Subject::new(); { let observer1 = Rc::new(ConcreteObserver { id: "1".to_string() }); let observer2 = Rc::new(ConcreteObserver { id: "2".to_string() }); subject.subscribe(Rc::downgrade(&observer1)); subject.subscribe(Rc::downgrade(&observer2)); subject.notify_all("Hello observers!"); } // Observers dropped here subject.notify_all("Anyone still listening?"); // Dead observers cleaned up
}

