Now let's store multiple temperature readings efficiently: use heapless::Vec;
use heapless::pool::{Pool, Node}; /// Fixed-capacity temperature buffer for embedded systems
pub struct TemperatureBuffer<const N: usize> { readings: Vec<Temperature, N>, total_readings: u32, // Track total for statistics
} impl<const N: usize> TemperatureBuffer<N> { /// Create new buffer with compile-time capacity pub const fn new() -> Self { Self { readings: Vec::new(), total_readings: 0, } } /// Add a temperature reading (circular buffer behavior) pub fn push(&mut self, temperature: Temperature) { if self.readings.len() < N { // Buffer not full yet - just add self.readings.push(temperature).ok(); } else { // Buffer full - use circular indexing (more efficient than remove(0)) let oldest_index = (self.total_readings as usize) % N; self.readings[oldest_index] = temperature; } self.total_readings += 1; } /// Get current number of readings pub fn len(&self) -> usize { self.readings.len() } /// Check if buffer is empty pub fn is_empty(&self) -> bool { self.readings.is_empty() } /// Get buffer capacity pub const fn capacity(&self) -> usize { N } /// Get the latest reading pub fn latest(&self) -> Option<Temperature> { self.readings.last().copied() } /// Get the oldest reading in buffer pub fn oldest(&self) -> Option<Temperature> { self.readings.first().copied() } /// Calculate average temperature pub fn average(&self) -> Option<Temperature> { if self.readings.is_empty() { return None; } let sum: i32 = self.readings.iter() .map(|t| t.celsius_tenths as i32) .sum(); let avg_tenths = sum / self.readings.len() as i32; Some(Temperature { celsius_tenths: avg_tenths as i16 }) } /// Find minimum temperature in buffer pub fn min(&self) -> Option<Temperature> { self.readings.iter() .min_by_key(|t| t.celsius_tenths) .copied() } /// Find maximum temperature in buffer pub fn max(&self) -> Option<Temperature> { self.readings.iter() .max_by_key(|t| t.celsius_tenths) .copied() } /// Get total readings processed (including overwritten ones) pub fn total_readings(&self) -> u32 { self.total_readings } /// Clear all readings pub fn clear(&mut self) { self.readings.clear(); self.total_readings = 0; } /// Get statistics summary pub fn stats(&self) -> Option<TemperatureStats> { if self.readings.is_empty() { return None; } Some(TemperatureStats { count: self.readings.len(), total_count: self.total_readings, average: self.average()?, min: self.min()?, max: self.max()?, }) }
} /// Statistics summary for temperature readings
#[derive(Debug, Clone, Copy)]
pub struct TemperatureStats { pub count: usize, // Current readings in buffer pub total_count: u32, // Total readings ever processed pub average: Temperature, pub min: Temperature, pub max: Temperature,
} impl fmt::Display for TemperatureStats { fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result { write!(f, "Stats: {} readings (total: {}), Avg: {}, Min: {}, Max: {}", self.count, self.total_count, self.average, self.min, self.max ) }
}

