Embedded systems benefit from compile-time configuration: /// System configuration computed at compile time
pub struct SystemConfig; impl SystemConfig { /// ESP32-C3 system clock frequency pub const CLOCK_HZ: u32 = 160_000_000; // 160 MHz /// Temperature monitoring configuration pub const TEMP_SAMPLE_RATE_HZ: u32 = 1; // 1 reading per second pub const TEMP_BUFFER_SIZE: usize = 60; // 1 minute of readings pub const TEMP_WARNING_THRESHOLD: f32 = 52.0; // 52°C warning threshold pub const TEMP_CRITICAL_THRESHOLD: f32 = 100.0; // 100°C critical threshold /// Calculate timer interval for sampling rate pub const fn sample_interval_ms() -> u32 { 1000 / Self::TEMP_SAMPLE_RATE_HZ } /// Create temperature thresholds at compile time pub const fn warning_threshold() -> Temperature { Temperature::from_celsius(Self::TEMP_WARNING_THRESHOLD) } pub const fn critical_threshold() -> Temperature { Temperature::from_celsius(Self::TEMP_CRITICAL_THRESHOLD) } /// Validate buffer size is reasonable pub const fn validate_buffer_size() -> bool { // Buffer should hold 1-300 seconds of data Self::TEMP_BUFFER_SIZE >= Self::TEMP_SAMPLE_RATE_HZ as usize && Self::TEMP_BUFFER_SIZE <= (Self::TEMP_SAMPLE_RATE_HZ * 300) as usize }
} // Compile-time assertions (will fail at compile time if invalid)
