} impl TemperatureStats { pub fn from_buffer<const N: usize>( buffer: &TemperatureBuffer<N>, timestamp_ms: u32 ) -> Option<Self> { if buffer.len() == 0 { return None; } let min = buffer.min()?.celsius(); let max = buffer.max()?.celsius(); let avg = buffer.average()?.celsius(); Some(Self { count: buffer.len() as u16, total_count: buffer.total_readings(), min_celsius: min, max_celsius: max, avg_celsius: avg, timestamp_ms, }) }
}

