For bandwidth-constrained applications, binary serialization is more efficient: // src/binary_comm.rs - Binary communication with postcard
#![cfg_attr(not(test), no_std)] use heapless::Vec;
use serde::{Deserialize, Serialize};
use postcard; use crate::communication::{Command, Response}; /// Binary communication handler
pub struct BinaryComm; impl BinaryComm { /// Serialize command to binary format pub fn command_to_binary(command: &Command) -> Result<Vec<u8, 64>, postcard::Error> { postcard::to_vec(command) } /// Deserialize command from binary format pub fn binary_to_command(data: &[u8]) -> Result<Command, postcard::Error> { postcard::from_bytes(data) } /// Serialize response to binary format pub fn response_to_binary(response: &Response) -> Result<Vec<u8, 256>, postcard::Error> { postcard::to_vec(response) } /// Deserialize response from binary format pub fn binary_to_response(data: &[u8]) -> Result<Response, postcard::Error> { postcard::from_bytes(data) } /// Get size of serialized command pub fn command_size(command: &Command) -> usize { Self::command_to_binary(command) .map(|v| v.len()) .unwrap_or(0) } /// Get size of serialized response pub fn response_size(response: &Response) -> usize { Self::response_to_binary(response) .map(|v| v.len()) .unwrap_or(0) }
} #[cfg(test)]
mod tests { use super::*; use crate::temperature::{Temperature, TemperatureReading}; #[test] fn test_binary_command_serialization() { let command = Command::SetSampleRate { rate_hz: 5 }; // Serialize to binary let binary = BinaryComm::command_to_binary(&command).unwrap(); // Deserialize back let deserialized = BinaryComm::binary_to_command(&binary).unwrap(); if let Command::SetSampleRate { rate_hz } = deserialized { assert_eq!(rate_hz, 5); } else { panic!("Deserialization failed"); } } #[test] fn test_binary_response_serialization() { let temp = Temperature::from_celsius(25.0); let reading = TemperatureReading::new(temp, 1000, 0); let response = Response::Reading(reading); // Serialize to binary let binary = BinaryComm::response_to_binary(&response).unwrap(); // Should be much smaller than JSON println!("Binary size: {} bytes", binary.len()); assert!(binary.len() < 20); // Much smaller than JSON // Deserialize back let deserialized = BinaryComm::binary_to_response(&binary).unwrap(); if let Response::Reading(r) = deserialized { assert!((r.temperature.celsius() - 25.0).abs() < 0.1); assert_eq!(r.timestamp_ms, 1000); } else { panic!("Deserialization failed"); } } #[test] fn test_size_comparison() { let temp = Temperature::from_celsius(23.5); let reading = TemperatureReading::new(temp, 1000, 0); let response = Response::Reading(reading); // Binary size let binary_size = BinaryComm::response_size(&response); // JSON size (approximate) let json = serde_json_core::to_string::<_, 256>(&response).unwrap(); let json_size = json.len(); println!("Binary: {} bytes, JSON: {} bytes", binary_size, json_size); println!("Binary is {}% smaller", ((json_size - binary_size) * 100) / json_size); assert!(binary_size < json_size); assert!(binary_size < 16); // Binary should be very compact }
}

