#[derive(Debug, Clone, PartialEq)]
pub enum Operation { Add, Subtract, Multiply, Divide,
} pub struct Calculator { precision: usize,
} impl Calculator { pub fn new() -> Self { Self { precision: 2 } } pub fn with_precision(precision: usize) -> Self { Self { precision } } pub fn calculate(&self, op: Operation, a: f64, b: f64) -> Result<f64, String> { let result = match op { Operation::Add => a + b, Operation::Subtract => a - b, Operation::Multiply => a * b, Operation::Divide => { if b == 0.0 { return Err("Division by zero".to_string()); } a / b } }; Ok(self.round_to_precision(result)) } fn round_to_precision(&self, value: f64) -> f64 { let multiplier = 10_f64.powi(self.precision as i32); (value * multiplier).round() / multiplier } pub fn chain_operations(&self, initial: f64, operations: Vec<(Operation, f64)>) -> Result<f64, String> { operations.iter().try_fold(initial, |acc, (op, value)| { self.calculate(op.clone(), acc, *value) }) }
} impl Default for Calculator { fn default() -> Self { Self::new() }
}

