Macros use pattern matching with specific fragment specifiers: 1. item - Items like functions, structs, modules macro_rules! create_function { ($func_name:ident) => { fn $func_name() { println!("You called {}!", stringify!($func_name)); } };
} create_function!(foo);
foo(); // Prints: You called foo! 2. block - Code blocks macro_rules! time_it { ($block:block) => { let start = std::time::Instant::now(); $block println!("Took: {:?}", start.elapsed()); };
} time_it!({ std::thread::sleep(std::time::Duration::from_millis(100)); println!("Work done!");
}); 3. stmt - Statements macro_rules! debug_stmt { ($stmt:stmt) => { println!("Executing: {}", stringify!($stmt)); $stmt };
} debug_stmt!(let x = 42;); 4. expr - Expressions macro_rules! double { ($e:expr) => { $e * 2 };
} let result = double!(5 + 3); // 16 Note: Edition 2024 Change : The expr fragment now also matches const and _ expressions. For backwards compatibility, use expr_2021 if you need the old behavior that doesn't match these expressions. 5. ty - Types macro_rules! create_struct { ($name:ident, $field_type:ty) => { struct $name { value: $field_type, } };
} create_struct!(MyStruct, i32); 6. ident - Identifiers macro_rules! getter { ($field:ident) => { fn $field(&self) -> &str { &self.$field } };
} 7. path - Paths like std::vec::Vec macro_rules! use_type { ($path:path) => { let _instance: $path = Default::default(); };
} use_type!(std::collections::HashMap<String, i32>); 8. literal - Literal values macro_rules! print_literal { ($lit:literal) => { println!("Literal: {}", $lit); };
} print_literal!("hello");
print_literal!(42); 9. tt - Token trees (any valid tokens) macro_rules! capture_tokens { ($($tt:tt)*) => { println!("Tokens: {}", stringify!($($tt)*)); };
} capture_tokens!(fn main() { println!("hello"); }); 10. pat - Patterns macro_rules! match_pattern { ($val:expr, $($pat:pat => $result:expr),+) => { match $val { $($pat => $result,)+ } };
} let x = match_pattern!(5, 0..=3 => "low", 4..=6 => "medium", _ => "high"
); 11. vis - Visibility qualifiers macro_rules! make_struct { ($vis:vis struct $name:ident) => { $vis struct $name { value: i32, } };
} make_struct!(pub struct PublicStruct); 12. lifetime - Lifetime parameters macro_rules! with_lifetime { ($lt:lifetime) => { struct Ref<$lt> { data: &$lt str, } };
} with_lifetime!('a); 13. meta - Attributes macro_rules! with_attributes { ($(#[$meta:meta])* struct $name:ident) => { $(#[$meta])* struct $name { value: i32, } };
