use std::thread; fn share_immutable_data() { let data = Arc::new(vec![1, 2, 3, 4, 5]); let mut handles = vec![]; for i in 0..3 { let data_clone = Arc::clone(&data); let handle = thread::spawn(move || { println!("Thread {}: sum = {}", i, data_clone.iter().sum::<i32>()); }); handles.push(handle); } for handle in handles { handle.join().unwrap(); }
} Key properties of Arc: Reference counting is atomic (thread-safe) Cloning is cheap (only increments counter) Data is immutable by default Memory freed when last reference drops

