Error handling follows the same patterns with async-specific considerations: use std::time::Duration;
use tokio::time::timeout; async fn with_timeout() -> Result<String, Box<dyn std::error::Error>> { // Timeout wraps the future timeout(Duration::from_secs(5), long_operation()).await?
} async fn long_operation() -> Result<String, std::io::Error> { // Simulated long operation tokio::time::sleep(Duration::from_secs(2)).await; Ok("Completed".to_string())
} // Retry with exponential backoff
async fn retry_operation<F, Fut, T, E>( mut f: F, max_attempts: u32,
) -> Result<T, E>
where F: FnMut() -> Fut, Fut: Future<Output = Result<T, E>>, E: std::fmt::Debug,
{ let mut delay = Duration::from_millis(100); for attempt in 1..=max_attempts { match f().await { Ok(val) => return Ok(val), Err(e) if attempt == max_attempts => return Err(e), Err(e) => { eprintln!("Attempt {} failed: {:?}, retrying...", attempt, e); tokio::time::sleep(delay).await; delay *= 2; // Exponential backoff } } } unreachable!()
}

